INSERT INTO `prof_quali_tbl` (`prof_q_id`, `prof_q_name`, `prof_q_description`) VALUES
(1, 'PhD. Ed', 'අධ්‍යාපනය පිළිබඳ දර්ශනශූරී උපාධිය(PhD Ed)'),
(2, 'MPhil. Ed', 'අධ්‍යාපනය පිළිබද දර්ශනපති උපාධිය(MPhil Ed)'),
(3, 'MEd', 'අධ්‍යාපනපති උපාධිය(MEd)'),
(4, 'MA in Ed', 'අධ්‍යාපනය පිළිබද ශ්‍රාස්ත්‍රපති උපාධිය(MA in Ed)'),
(5, '', 'අධ්‍යාපන කළමනාකරණය පිළිබද විද්‍යාපති උපාධිය '),
(6, '', 'ගුරු අධ්‍යාපනය පිළිබඳ ශ්‍රාස්ත්‍රපති උපාධිය '),
